namespace sv_a74244d6e4294407851dfedd76239611.Models;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class Notification
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public required string Title { get; init; }
    public required string Message { get; init; }
    public Severity Severity { get; init; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; init; } = DateTime.UtcNow;
}

using sv_a74244d6e4294407851dfedd76239611.Models;

namespace sv_a74244d6e4294407851dfedd76239611.Services;

/// <summary>
/// Scoped per circuit. Holds notification state and notifies all
/// subscribers when any mutation occurs.
/// </summary>
public class NotificationHub
{
    private readonly List<Notification> _notifications = [];
    private readonly object _lock = new();

    /// <summary>
    /// Raised after every mutation so every subscribed component
    /// can re-render. Handlers run on a non-UI thread when the
    /// mutation originates from a timer, so components must call
    /// <c>InvokeAsync(StateHasChanged)</c> inside their handler.
    /// </summary>
    public event Func<Task>? OnChange;

    public IReadOnlyList<Notification> Notifications
    {
        get { lock (_lock) return _notifications.ToList(); }
    }

    public int GetUnreadCount()
    {
        lock (_lock) return _notifications.Count(n => !n.IsRead);
    }

    public async Task AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Insert(0, new Notification
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        await NotifySubscribers();
    }

    public async Task MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var n = _notifications.FirstOrDefault(x => x.Id == id);
            if (n is not null) n.IsRead = true;
        }
        await NotifySubscribers();
    }

    public async Task MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications) n.IsRead = true;
        }
        await NotifySubscribers();
    }

    public async Task DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        await NotifySubscribers();
    }

    private async Task NotifySubscribers()
    {
        if (OnChange is not null)
        {
            // Invoke each subscriber individually so one failure
            // doesn't prevent others from updating.
            foreach (var handler in OnChange.GetInvocationList().Cast<Func<Task>>())
            {
                try
                {
                    await handler();
                }
                catch (ObjectDisposedException)
                {
                    // Component already disposed; safe to ignore.
                }
            }
        }
    }
}

using sv_a74244d6e4294407851dfedd76239611.Models;

namespace sv_a74244d6e4294407851dfedd76239611.Services;

/// <summary>
/// Scoped service that pushes a random notification every 15 seconds.
/// Started/stopped by the Dashboard page so it only runs while the
/// dashboard is visible.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    private static readonly string[] Titles =
    [
        "CPU spike detected",
        "Disk usage warning",
        "New user signed up",
        "Deployment completed",
        "Certificate expiring soon",
        "Backup finished",
        "Memory threshold exceeded",
        "Service health check failed"
    ];

    private static readonly string[] Messages =
    [
        "Check the monitoring dashboard for details.",
        "Immediate attention may be required.",
        "Everything looks good — informational only.",
        "Review logs for additional context.",
        "Automated remediation has been triggered."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_cts is not null) return; // already running

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));

        _ = RunAsync(_cts.Token);
    }

    private async Task RunAsync(CancellationToken ct)
    {
        var rng = new Random();
        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct)) break;

                var title = Titles[rng.Next(Titles.Length)];
                var message = Messages[rng.Next(Messages.Length)];
                var severity = (Severity)rng.Next(3);

                await _hub.AddNotification(title, message, severity);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
        _cts = null;
        _timer = null;
    }
}

