toolArgs.file_text:
@* Interactive island — the bell needs its own render mode because
   the layout is static (no @rendermode on MainLayout). *@
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationHub Hub

<a href="notifications" class="notification-bell" title="Notifications">
    🔔
    @if (_unreadCount > 0)
    {
        <span class="badge">@(_unreadCount > 99 ? "99+" : _unreadCount)</span>
    }
</a>

@code {
    private int _unreadCount;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        Hub.OnChange += OnHubChanged;
    }

    /// <summary>
    /// Called from any thread (including timer threads).
    /// InvokeAsync marshals the StateHasChanged call onto the
    /// Blazor synchronization context for this circuit.
    /// </summary>
    private async Task OnHubChanged()
    {
        _unreadCount = Hub.GetUnreadCount();
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}

