toolArgs.file_text:
@* Interactive island for the dashboard summary panel. *@
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationHub Hub

<div class="summary-panel">
    <h5>Recent Unread</h5>

    @if (_recent.Count == 0)
    {
        <p class="text-muted">No unread notifications.</p>
    }
    else
    {
        @foreach (var n in _recent)
        {
            <div class="summary-item severity-@n.Severity.ToString().ToLowerInvariant()">
                <div class="d-flex justify-content-between align-items-start">
                    <div>
                        <strong>@n.Title</strong>
                        <small class="text-muted d-block">@n.Timestamp.ToString("g")</small>
                        <span>@n.Message</span>
                    </div>
                    <button class="btn btn-sm btn-outline-danger ms-2"
                            @onclick="() => Dismiss(n.Id)">
                        ✕
                    </button>
                </div>
            </div>
        }
    }
</div>

@code {
    private List<Models.Notification> _recent = [];

    protected override void OnInitialized()
    {
        Refresh();
        Hub.OnChange += OnHubChanged;
    }

    private void Refresh()
    {
        _recent = Hub.Notifications
            .Where(n => !n.IsRead)
            .OrderByDescending(n => n.Timestamp)
            .Take(3)
            .ToList();
    }

    private async Task Dismiss(Guid id) => await Hub.DismissNotification(id);

    private async Task OnHubChanged()
    {
        Refresh();
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}

