+                        <small class="text-muted d-block">@n.Timestamp.ToString("g")</small>
+                        <p class="mb-0">@n.Message</p>
+                    </div>
+                    <div class="btn-group ms-2">
+                        @if (!n.IsRead)
+                        {
+                            <button class="btn btn-sm btn-outline-primary"
+                                    @onclick="() => MarkRead(n.Id)">
+                                Mark Read
+                            </button>
+                        }
+                        <button class="btn btn-sm btn-outline-danger"
+                                @onclick="() => Dismiss(n.Id)">
+                            Dismiss
+                        </button>
+                    </div>
+                </div>
+            </div>
+        }
+    }
+}
+
+@code {
+    private List<Models.Notification> _notifications = [];
+    private IOrderedEnumerable<IGrouping<Models.Severity, Models.Notification>> _grouped = default!;
+    private int _unreadCount;
+
+    protected override void OnInitialized()
+    {
+        Refresh();
+        Hub.OnChange += OnHubChanged;
+    }
+
+    private void Refresh()
+    {
+        _notifications = Hub.Notifications.ToList();
+        _unreadCount = Hub.GetUnreadCount();
+        _grouped = _notifications
+            .GroupBy(n => n.Severity)
+            .OrderByDescending(g => g.Key);
+    }
+
+    private async Task MarkRead(Guid id) => await Hub.MarkAsRead(id);
+    private async Task MarkAllRead() => await Hub.MarkAllRead();
+    private async Task Dismiss(Guid id) => await Hub.DismissNotification(id);
+
+    private async Task OnHubChanged()
+    {
+        Refresh();
+        await InvokeAsync(StateHasChanged);
+    }
+
+    public void Dispose()
+    {
+        Hub.OnChange -= OnHubChanged;
+    }
+}
+

