toolArgs.file_text:
@page "/dashboard"
@rendermode InteractiveServer
@implements IDisposable
@inject SimulatorService Simulator

<PageTitle>Dashboard</PageTitle>

<h3 class="mb-4">Dashboard</h3>

<div class="row">
    <div class="col-md-6">
        <NotificationSummaryPanel />
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Simulation</h5>
                <p class="card-text text-muted">
                    A random notification is generated every 15 seconds while
                    this page is open. Watch the bell badge and summary panel
                    update in real time.
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        Simulator.Start();
    }

    public void Dispose()
    {
        Simulator.Dispose();
    }
}

